(() => {
  let postBtns = [...document.querySelectorAll('[title="Post"], [aria-label="Post"]')];
  if(postBtns.length === 0) {
    alert('No Post buttons found');
    return;
  }

  let rows = postBtns.map((btn, i) => {
    let tr = btn.closest('tr');
    let cells = tr? [...tr.querySelectorAll('td, [role="gridcell"]')] : [];
    let col2 = cells[1]?.innerText.trim() || '';
    let col3 = cells[2]?.innerText.trim() || '';
    let username = cells[9]?.innerText.trim() || 'NoUser';
    return {index: i, btn: btn, username: username, info: `${col2} | ${col3}`};
  });

  let list = rows.map(r => `${r.index+1}. User: ${r.username} | ${r.info}`).join('\n');
  let choice = prompt(`Found ${rows.length} rows:\n\n${list}\n\nEnter row numbers: 1,3,5 OR usernames: john,ali OR type 'all'`);
  if(!choice) return;

  let selectedRows;
  choice = choice.toLowerCase().trim();
  if(choice === 'all') {
    selectedRows = rows;
  } else if(choice.includes(',')) {
    let inputs = choice.split(',').map(s => s.trim());
    selectedRows = rows.filter(r =>
      inputs.includes(String(r.index+1)) ||
      inputs.includes(r.username.toLowerCase())
    );
  } else {
    selectedRows = rows.filter(r =>
      String(r.index+1) === choice ||
      r.username.toLowerCase() === choice
    );
  }

  if(selectedRows.length === 0) {
    alert('No matching users/rows found');
    return;
  }

  let password = prompt(`Selected ${selectedRows.length} users. Enter password:`);
  if(password === null) return;

  alert(`Starting for users: ${selectedRows.map(r=>r.username).join(', ')}`);

  const wait = ms => new Promise(r => setTimeout(r, ms));
  const findBtnByText = (text) => [...document.querySelectorAll('button, a[role="button"]')]
    .find(b => b.innerText.trim().toLowerCase() === text.toLowerCase());

  async function runPosts() {
    for(let i = 0; i < selectedRows.length; i++) {
      let {btn, username} = selectedRows[i];
      console.log(`Processing ${i+1}/${selectedRows.length} - User: ${username}`);
      btn.click();
      await wait(2000);

      let yesBtn = findBtnByText('Yes') || document.querySelector('button[title="Yes"]');
      if(yesBtn) { yesBtn.click(); await wait(1000); }

      let pwdInput = document.querySelector('input[type="password"]');
      if(pwdInput) {
        pwdInput.value = password;
        pwdInput.dispatchEvent(new Event('input', {bubbles: true}));
        await wait(500);
      }

      let postConfirm = findBtnByText('Post') || document.querySelector('button[title="Post"]');
      if(postConfirm) { postConfirm.click(); }
      await wait(3000);
    }
    alert('Done! Processed ' + selectedRows.length + ' users.');
  }

  runPosts();
})();

