  if(editBtns.length === 0) { alert('Edit button not found'); return; }

  let rows = editBtns.map((btn, i) => {
    let tr = btn.closest('tr');
    let cells = [...tr.querySelectorAll('td')];
    return {
      index: i,
      btn: btn,
      prdNo: cells[0]?.innerText.trim() || '',
      itemName: cells[4]?.innerText.trim() || ''
    };
  });

  let choice = prompt(`Select vouchers:\n${rows.map(r => `${r.index+1}. ${r.prdNo} | ${r.itemName}`).join('\n')}\n\nEnter: 1,3 OR 'all'`);
  if(!choice) return;

  let selectedRows = choice.toLowerCase() === 'all'? rows :
    choice.split(',').map(s => s.trim().toUpperCase()).flatMap(input =>
      rows.filter(r => String(r.index+1) === input || r.prdNo.toUpperCase() === input)
    );

  if(selectedRows.length === 0) { alert('No rows selected'); return; }

  let password = prompt(`Selected ${selectedRows.length} vouchers. Enter password:`);
  if(password === null) return;

  const wait = ms => new Promise(r => setTimeout(r, ms));
  const findBtn = (text) => [...document.querySelectorAll('button')].find(b => b.innerText.trim().toLowerCase().includes(text.toLowerCase()));

  async function setNgInput(el, value) {
    const nativeSetter = Object.getOwnPropertyDescriptor(window.HTMLInputElement.prototype, 'value').set;
    nativeSetter.call(el, value);
    el.dispatchEvent(new Event('input', { bubbles: true }));
    el.dispatchEvent(new Event('change', { bubbles: true }));
    el.dispatchEvent(new Event('blur', { bubbles: true }));
  }

  async function processVoucher({prdNo, itemName}) {
    console.log(`\n=== Processing: ${prdNo} ===`);

    let postRowBtn = [...document.querySelectorAll('tr')].find(tr => tr.innerText.includes(prdNo))?.querySelector('button[title="Post"]');
    if(!postRowBtn) { console.error('Post button not found for', prdNo); return; }
    postRowBtn.click();
    console.log('Step 1: Clicked Post');
    await wait(500);

    let yesBtn;
    for(let i = 0; i < 10; i++) {
      yesBtn = findBtn('Yes');
      if(yesBtn) break;
      await wait(500);
    }
    if(!yesBtn) { console.error('Yes button not found'); return; }
    yesBtn.click();
    console.log('Step 2: Clicked Yes');
    await wait(500);

    let pwdInput;
    for(let i = 0; i < 20; i++) {
      pwdInput = document.querySelector('input[name="specialPassword"]');
      if(pwdInput && pwdInput.offsetParent !== null) break;
      await wait(300);
    }
    if(!pwdInput) { console.error('Password field not found'); return; }

    await setNgInput(pwdInput, password);
    console.log('Step 3: Password entered -', pwdInput.value ? 'SUCCESS' : 'FAILED');
    await wait(400);

    let postBtn = findBtn('Post');
    if(!postBtn) { console.error('Post confirm button not found'); return; }
    postBtn.click();
    console.log('Step 4: Clicked Post');
    await wait(500);

    await wait(500);
    console.log(`=== Done: ${prdNo} ===\n`);
  }

  async function runAll() {
    for(let i = 0; i < selectedRows.length; i++) {
      await processVoucher(selectedRows[i]);
      await wait(500);
    }
    alert('All vouchers posted!');
  }

  runAll();
})();
